     1→import { BrowserRouter, Routes, Route } from 'react-router-dom';
     2→import { useEffect, lazy, Suspense } from 'react';
     3→import { Layout } from './components/Layout';
     4→import { StoreErrorBoundary } from './components/StoreErrorBoundary';
     5→import { migrateToIndexedDB, isMigrationNeeded } from './services/migration';
     6→import { UndoToastContainer } from './components/UndoToast';
     7→import { useUndoStore } from './stores/useUndoStore';
     8→import { BackupOnboardingModal } from './components/BackupOnboardingModal';
     9→import { useBackupOnboarding } from './hooks/useBackupOnboarding';
    10→import { OnboardingModal } from './components/OnboardingModal';
    11→import { useSettingsStore } from './stores/useSettingsStore';
    12→
    13→// Lazy load all pages for code splitting (including Dashboard)
    14→const Dashboard = lazy(() => import('./pages/Dashboard').then((m) => ({ default: m.Dashboard })));
    15→const Tasks = lazy(() => import('./pages/Tasks').then((m) => ({ default: m.Tasks })));
    16→const Settings = lazy(() => import('./pages/Settings').then((m) => ({ default: m.Settings })));
    17→const Notes = lazy(() => import('./pages/Notes').then((m) => ({ default: m.Notes })));
    18→const GraphView = lazy(() => import('./pages/GraphView'));
    19→const Diagrams = lazy(() => import('./pages/Diagrams'));
    20→const DiagramEditor = lazy(() => import('./pages/DiagramEditor'));
    21→const Forms = lazy(() => import('./pages/Forms'));
    22→const FormBuilder = lazy(() => import('./pages/FormBuilder'));
    23→const FormFiller = lazy(() => import('./pages/FormFiller'));
    24→const FormResponses = lazy(() => import('./pages/FormResponses'));
    25→const TimeTracking = lazy(() => import('./pages/TimeTracking').then((m) => ({ default: m.TimeTracking })));
    26→const LinkLibrary = lazy(() => import('./pages/LinkLibrary'));
    27→const Automations = lazy(() => import('./pages/Automations').then((m) => ({ default: m.Automations })));
    28→
    29→// Loading fallback component
    30→const PageLoader = () => (
    31→  <div className="flex items-center justify-center min-h-[60vh]">
    32→    <div className="text-center">
    33→      <div className="inline-block h-12 w-12 animate-spin rounded-full border-4 border-solid border-primary-cyan border-r-transparent align-[-0.125em] motion-reduce:animate-[spin_1.5s_linear_infinite]"></div>
    34→      <p className="mt-4 text-sm text-text-light-secondary dark:text-text-dark-secondary">Loading...</p>
    35→    </div>
    36→  </div>
    37→);
    38→
    39→/**
    40→ * Main App Component with React Router
    41→ * Uses Layout component to provide consistent header/footer
    42→ */
    43→function App() {
    44→  // Get undo toasts from store
    45→  const toasts = useUndoStore((state) => state.toasts);
    46→  const dismissToast = useUndoStore((state) => state.dismissToast);
    47→
    48→  // Backup onboarding
    49→  const { shouldShowModal, dismissModal } = useBackupOnboarding();
    50→
    51→  // First-time onboarding
    52→  const onboardingComplete = useSettingsStore((state) => state.onboardingComplete);
    53→  const setOnboardingComplete = useSettingsStore((state) => state.setOnboardingComplete);
    54→
    55→  // Run migration and initialize auto-save on app startup
    56→  useEffect(() => {
    57→    const initialize = async () => {
    58→      // Run migration if needed
    59→      if (isMigrationNeeded()) {
    60→        console.log('🚀 Migration needed, starting...');
    61→        const result = await migrateToIndexedDB();
    62→        if (result.success) {
    63→          console.log('✅ Migration complete');
    64→        } else {
    65→          console.error('❌ Migration failed:', result.errors);
    66→        }
    67→      }
    68→
    69→      // Initialize auto-save (dynamic import to reduce main bundle)
    70→      const { autoSaveManager } = await import('./services/autoSave');
    71→      await autoSaveManager.initialize();
    72→    };
    73→
    74→    initialize();
    75→  }, []);
    76→
    77→  return (
    78→    <BrowserRouter>
    79→      <Layout>
    80→        <Suspense fallback={<PageLoader />}>
    81→          <Routes>
    82→            <Route path="/" element={<Dashboard />} />
    83→            <Route
    84→              path="/notes"
    85→              element={
    86→                <StoreErrorBoundary storeName="notes">
    87→                  <Notes />
    88→                </StoreErrorBoundary>
    89→              }
    90→            />
    91→            <Route
    92→              path="/graph"
    93→              element={
    94→                <StoreErrorBoundary storeName="notes">
    95→                  <GraphView />
    96→                </StoreErrorBoundary>
    97→              }
    98→            />
    99→            <Route
   100→              path="/diagrams"
   101→              element={
   102→                <StoreErrorBoundary storeName="diagrams">
   103→                  <Diagrams />
   104→                </StoreErrorBoundary>
   105→              }
   106→            />
   107→            <Route
   108→              path="/diagrams/:id"
   109→              element={
   110→                <StoreErrorBoundary storeName="diagrams">
   111→                  <DiagramEditor />
   112→                </StoreErrorBoundary>
   113→              }
   114→            />
   115→            <Route
   116→              path="/forms"
   117→              element={
   118→                <StoreErrorBoundary storeName="forms">
   119→                  <Forms />
   120→                </StoreErrorBoundary>
   121→              }
   122→            />
   123→            <Route
   124→              path="/forms/:id/edit"
   125→              element={
   126→                <StoreErrorBoundary storeName="forms">
   127→                  <FormBuilder />
   128→                </StoreErrorBoundary>
   129→              }
   130→            />
   131→            <Route
   132→              path="/forms/:id/fill"
   133→              element={
   134→                <StoreErrorBoundary storeName="forms">
   135→                  <FormFiller />
   136→                </StoreErrorBoundary>
   137→              }
   138→            />
   139→            <Route
   140→              path="/forms/:id/responses"
   141→              element={
   142→                <StoreErrorBoundary storeName="forms">
   143→                  <FormResponses />
   144→                </StoreErrorBoundary>
   145→              }
   146→            />
   147→            <Route
   148→              path="/tasks"
   149→              element={
   150→                <StoreErrorBoundary storeName="kanban">
   151→                  <Tasks />
   152→                </StoreErrorBoundary>
   153→              }
   154→            />
   155→            <Route path="/settings" element={<Settings />} />
   156→            <Route
   157→              path="/schedule"
   158→              element={
   159→                <StoreErrorBoundary storeName="calendar">
   160→                  <TimeTracking />
   161→                </StoreErrorBoundary>
   162→              }
   163→            />
   164→            <Route path="/links" element={<LinkLibrary />} />
   165→            <Route
   166→              path="/automations"
   167→              element={
   168→                <StoreErrorBoundary storeName="automation">
   169→                  <Automations />
   170→                </StoreErrorBoundary>
   171→              }
   172→            />
   173→          </Routes>
   174→        </Suspense>
   175→      </Layout>
   176→
   177→      {/* Undo Toast Container - Global across all pages */}
   178→      <UndoToastContainer toasts={toasts} onDismiss={dismissToast} />
   179→
   180→      {/* First-Time Onboarding Modal */}
   181→      <OnboardingModal
   182→        isOpen={!onboardingComplete}
   183→        onClose={() => setOnboardingComplete(true)}
   184→      />
   185→
   186→      {/* Backup Onboarding Modal */}
   187→      <BackupOnboardingModal isOpen={shouldShowModal} onClose={dismissModal} />
   188→    </BrowserRouter>
   189→  );
   190→}
   191→
   192→export default App;
   193→

