        return DEFAULT_CARD_TEMPLATES;
      },
    }),
    {
      name: 'kanban-tasks',
      storage: createJSONStorage(() => createSyncedStorage()),
      version: 2, // Increment for dependency migration
      migrate: (persistedState: any, version: number) => {
        // Version 2: Migrate from global SimpleTaskDependency[] to task-level TaskDependency[]
        if (version < 2 && needsMigration(persistedState)) {
          log.info('Migrating dependencies from global array to task level');
          const migratedTasks = migrateDependenciesToTaskLevel(
            persistedState.tasks || [],
            persistedState.dependencies || []
          );

          return {
            ...persistedState,
            tasks: migratedTasks,
            dependencies: undefined, // Remove old dependencies field
          };
        }

        return persistedState;
      },
    }
  )
);

